// Comment represents a single user comment.
type Comment struct {
	Author string
	Text   template.HTML // Using template.HTML to allow rendering pre-sanitized HTML content.
}

// comments is our in-memory storage for user comments.
// Note: For actual user input, ensure robust HTML sanitization before
// converting input strings to template.HTML to prevent XSS vulnerabilities.
var comments = []Comment{
	{Author: "Alice", Text: template.HTML("This is a <b>great</b> example of basic formatting!")},
	{Author: "Bob", Text: template.HTML("I found this very <i>helpful</i>.<br>Thanks for sharing!")},
	{Author: "Charlie", Text: template.HTML("Just a regular comment with no special formatting.")},
	{Author: "David", Text: template.HTML("Another comment with <strong>strong</strong> emphasis and a list item:<ul><li>Item 1</li><li>Item 2</li></ul>")},
	{Author: "Eve", Text: template.HTML("A comment with a <a href='https://go.dev' target='_blank'>link to Go</a>.")},
}

// tmpl holds our parsed HTML template.
var tmpl = template.Must(template.ParseFiles("comments.html"))

// commentsHandler is the HTTP handler that displays the user comments.
func commentsHandler(w http.ResponseWriter, r *http.Request) {
	// Set the Content-Type header to indicate we're serving HTML.
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Execute the template, passing the comments slice as data.
	if err := tmpl.Execute(w, comments); err != nil {
		log.Printf("Error executing template: %v", err)
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

func main() {
	// Register the handler for the root path.
	http.HandleFunc("/", commentsHandler)

	// Start the HTTP server.
	log.Println("Server starting on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

